13→// openRepo opens the git repository at the current directory (or GIT_DIR).
14→func openRepo() (*git.Repository, error) {
15→	dir := os.Getenv("GIT_DIR")
16→	if dir == "" {
17→		dir = "."
18→	}
19→	return git.PlainOpenWithOptions(dir, &git.PlainOpenOptions{
20→		DetectDotGit: true,
21→	})
22→}
23→
24→// openRepoOrDie opens the repository or prints a fatal error and exits.
25→func openRepoOrDie() *git.Repository {
26→	r, err := openRepo()
27→	if err != nil {
28→		fatal("%s", err)
29→	}
30→	return r
31→}
32→
33→// formatTime formats a time for git log/show output.
34→func formatTime(t time.Time) string {
35→	return t.Format("Mon Jan 2 15:04:05 2006 -0700")
36→}
37→
38→// nextVal consumes the next argument as a flag value, advancing *i.
39→// Returns the value and true, or empty and false if no next arg exists.
40→func nextVal(args []string, i *int) (string, bool) {
41→	if *i+1 < len(args) {
42→		*i++
43→		return args[*i], true
44→	}
45→	return "", false
46→}
47→
48→// firstLine returns the first line of s.
49→func firstLine(s string) string {
50→	if idx := strings.IndexByte(s, '\n'); idx >= 0 {
51→		return s[:idx]
52→	}
53→	return s
54→}
55→
56→// fatal prints a fatal error message to stderr and exits with code 128.
57→// Note: os.Exit skips deferred calls. This is acceptable for a CLI where
58→// defers are only closing file handles (reclaimed by the OS anyway).
59→// Do not add deferred writes (lockfiles, flush) that depend on running.
60→func fatal(format string, args ...any) {
61→	fmt.Fprintf(os.Stderr, "fatal: "+format+"\n", args...)
62→	os.Exit(128)
63→}
64→
65→// gitDir returns the .git directory path for the current working directory.
66→// In a bare repository (no .git subdirectory, but HEAD exists), returns ".".
67→// Note: this duplicates the walk in openRepo/DetectDotGit, but is needed by
68→// cmd_config.go which reads raw config files without opening a full repo.
69→func gitDir() string {
70→	dir := os.Getenv("GIT_DIR")
71→	if dir != "" {
72→		return dir
73→	}
74→	// Walk up to find .git
75→	wd, err := os.Getwd()
76→	if err != nil {
77→		return ".git"
78→	}
79→	for {
80→		candidate := filepath.Join(wd, ".git")
81→		if fi, err := os.Stat(candidate); err == nil && fi.IsDir() {
82→			return candidate
83→		}
84→		// Check for bare repo (HEAD file exists in current dir).
85→		if _, err := os.Stat(filepath.Join(wd, "HEAD")); err == nil {
86→			if _, err := os.Stat(filepath.Join(wd, "refs")); err == nil {
87→				return wd
88→			}
89→		}
90→		parent := filepath.Dir(wd)
91→		if parent == wd {
92→			break
93→		}
94→		wd = parent
95→	}
96→	return ".git"
97→}
