package main

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/go-git/go-git/v6"
)

// openRepo opens the git repository at the current directory (or GIT_DIR).
func openRepo() (*git.Repository, error) {
	dir := os.Getenv("GIT_DIR")
	if dir == "" {
		dir = "."
	}
	return git.PlainOpenWithOptions(dir, &git.PlainOpenOptions{
		DetectDotGit: true,
	})
}

// openRepoOrDie opens the repository or prints a fatal error and exits.
func openRepoOrDie() *git.Repository {
	r, err := openRepo()
	if err != nil {
		fatal("%s", err)
	}
	return r
}

// formatTime formats a time for git log/show output.
func formatTime(t time.Time) string {
	return t.Format("Mon Jan 2 15:04:05 2006 -0700")
}

// nextVal consumes the next argument as a flag value, advancing *i.
// Returns the value and true, or empty and false if no next arg exists.
func nextVal(args []string, i *int) (string, bool) {
	if *i+1 < len(args) {
		*i++
		return args[*i], true
	}
	return "", false
}

// firstLine returns the first line of s.
func firstLine(s string) string {
	if idx := strings.IndexByte(s, '\n'); idx >= 0 {
		return s[:idx]
	}
	return s
}

// fatal prints a fatal error message to stderr and exits with code 128.
// Note: os.Exit skips deferred calls. This is acceptable for a CLI where
// defers are only closing file handles (reclaimed by the OS anyway).
// Do not add deferred writes (lockfiles, flush) that depend on running.
func fatal(format string, args ...any) {
	fmt.Fprintf(os.Stderr, "fatal: "+format+"\n", args...)
	os.Exit(128)
}

// gitDir returns the .git directory path for the current working directory.
// In a bare repository (no .git subdirectory, but HEAD exists), returns ".".
// Note: this duplicates the walk in openRepo/DetectDotGit, but is needed by
// cmd_config.go which reads raw config files without opening a full repo.
func gitDir() string {
	dir := os.Getenv("GIT_DIR")
	if dir != "" {
		return dir
	}
	// Walk up to find .git
	wd, err := os.Getwd()
	if err != nil {
		return ".git"
	}
	for {
		candidate := filepath.Join(wd, ".git")
		if fi, err := os.Stat(candidate); err == nil && fi.IsDir() {
			return candidate
		}
		// Check for bare repo (HEAD file exists in current dir).
		if _, err := os.Stat(filepath.Join(wd, "HEAD")); err == nil {
			if _, err := os.Stat(filepath.Join(wd, "refs")); err == nil {
				return wd
			}
		}
		parent := filepath.Dir(wd)
		if parent == wd {
			break
		}
		wd = parent
	}
	return ".git"
}

type CloneOptions struct {
	// The (possibly remote) repository URL to clone from.
	URL string
	// Auth credentials, if required, to use with the remote repository.
	Auth transport.AuthMethod
	// Name of the remote to be added, by default `origin`.
	RemoteName string
	// Remote branch to clone.
	ReferenceName plumbing.ReferenceName
	// Fetch only ReferenceName if true.
	SingleBranch bool
	// Mirror clones the repository as a mirror.
	//
	// Compared to a bare clone, mirror not only maps local branches of the
	// source to local branches of the target, it maps all refs (including
	// remote-tracking branches, notes etc.) and sets up a refspec configuration
	// such that all these refs are overwritten by a git remote update in the
	// target repository.
	Mirror bool
	// No checkout of HEAD after clone if true.
	NoCheckout bool
	// Limit fetching to the specified number of commits.
	Depth int
	// RecurseSubmodules after the clone is created, initialize all submodules
	// within, using their default settings. This option is ignored if the
	// cloned repository does not have a worktree.
	RecurseSubmodules SubmoduleRecursivity
	// ShallowSubmodules limit cloning submodules to the 1 level of depth.
	// It matches the git command --shallow-submodules.
	ShallowSubmodules bool
	// Progress is where the human readable information sent by the server is
	// stored, if nil nothing is stored and the capability (if supported)
	// no-progress, is sent to the server to avoid send this information.
	Progress sideband.Progress
	// Tags describe how the tags will be fetched from the remote repository,
	// by default is AllTags.
	Tags plumbing.TagMode
	// InsecureSkipTLS skips ssl verify if protocol is https
	InsecureSkipTLS bool
	// CABundle specify additional ca bundle with system cert pool
	CABundle []byte
	// ProxyOptions provides info required for connecting to a proxy.
	ProxyOptions transport.ProxyOptions
	// When the repository to clone is on the local machine, instead of
	// using hard links, automatically setup .git/objects/info/alternates
	// to share the objects with the source repository.
	// The resulting repository starts out without any object of its own.
	// NOTE: this is a possibly dangerous operation; do not use it unless
	// you understand what it does.
	//
	// [Reference]: https://git-scm.com/docs/git-clone#Documentation/git-clone.txt---shared
	Shared bool
	// Filter requests that the server to send only a subset of the objects.
	// See https://git-scm.com/docs/git-clone#Documentation/git-clone.txt-code--filterltfilter-specgtcode
	Filter packp.Filter

