  1→package reflog
  2→
  3→import (
  4→	"bufio"
  5→	"bytes"
  6→	"fmt"
  7→	"io"
  8→	"strconv"
  9→	"strings"
 10→	"time"
 11→
 12→	"github.com/go-git/go-git/v6/plumbing"
 13→)
 14→
 15→// Signature represents an author or committer identity with a timestamp.
 16→// This mirrors object.Signature but is defined here to avoid an import cycle
 17→// (reflog -> object -> storer -> reflog).
 18→type Signature struct {
 19→	// Name represents a person name.
 20→	Name string
 21→	// Email is an email address.
 22→	Email string
 23→	// When is the timestamp of the signature.
 24→	When time.Time
 25→}
 26→
 27→// Entry represents a single reflog entry.
 28→type Entry struct {
 29→	// OldHash is the hash the reference pointed to before the change.
 30→	OldHash plumbing.Hash
 31→	// NewHash is the hash the reference points to after the change.
 32→	NewHash plumbing.Hash
 33→	// Committer holds the signature for the entry, including name, email and when it was created.
 34→	Committer Signature
 35→	// Message describes the action that caused the change (e.g. "commit: Add feature").
 36→	Message string
 37→}
 38→
 39→// Decoder reads reflog entries from a reader one at a time.
 40→type Decoder struct {
 41→	r *bufio.Reader
 42→}
 43→
 44→// NewDecoder creates a Decoder that reads reflog entries from r.
 45→func NewDecoder(r io.Reader) *Decoder {
 46→	return &Decoder{r: bufio.NewReader(r)}
 47→}
 48→
 49→// Next returns the next reflog entry. It returns io.EOF when there are no more entries.
 50→func (d *Decoder) Next() (*Entry, error) {
 51→	for {
 52→		line, err := d.r.ReadBytes('\n')
 53→		if err != nil && err != io.EOF {
 54→			return nil, err
 55→		}
 56→
 57→		line = bytes.TrimSuffix(line, []byte{'\n'})
 58→		if len(line) != 0 {
 59→			return decodeLine(line)
 60→		}
 61→
 62→		if err == io.EOF {
 63→			return nil, io.EOF
 64→		}
 65→	}
 66→}
 67→
 68→// Decode reads all reflog entries from the reader.
 69→// Entries are returned in file order (oldest first).
 70→func Decode(r io.Reader) ([]*Entry, error) {
 71→	if r == nil {
 72→		return nil, fmt.Errorf("reader is nil")
 73→	}
 74→	d := NewDecoder(r)
 75→	var entries []*Entry
 76→	for {
 77→		e, err := d.Next()
 78→		if err == io.EOF {
 79→			return entries, nil
 80→		}
 81→		if err != nil {
 82→			return entries, err
 83→		}
 84→		entries = append(entries, e)
 85→	}
 86→}
 87→
 88→// decodeLine parses a single reflog line.
 89→// Format: <old-hash> <new-hash> <name> <<email>> <unix-timestamp> <timezone>\t<message>
 90→func decodeLine(line []byte) (*Entry, error) {
 91→	e := &Entry{}
 92→
 93→	// Parse old hash (up to first space)
 94→	spaceIdx := bytes.IndexByte(line, ' ')
 95→	if spaceIdx == -1 {
 96→		return nil, fmt.Errorf("reflog entry too short")
 97→	}
 98→	oldHashStr := string(line[:spaceIdx])
 99→	if !plumbing.IsHash(oldHashStr) {
100→		return nil, fmt.Errorf("invalid old hash in reflog entry: %q", oldHashStr)
101→	}
102→	e.OldHash = plumbing.NewHash(oldHashStr)
103→	line = line[spaceIdx+1:]
104→
105→	// Parse new hash (up to next space)
106→	spaceIdx = bytes.IndexByte(line, ' ')
107→	if spaceIdx == -1 {
108→		return nil, fmt.Errorf("expected space after new hash")
109→	}
110→	newHashStr := string(line[:spaceIdx])
111→	if !plumbing.IsHash(newHashStr) {
112→		return nil, fmt.Errorf("invalid new hash in reflog entry: %q", newHashStr)
113→	}
114→	e.NewHash = plumbing.NewHash(newHashStr)
115→	line = line[spaceIdx+1:]
116→
117→	// Split on tab to separate signature from message
118→	sigBytes := line
119→	tabIdx := bytes.IndexByte(line, '\t')
120→	if tabIdx != -1 {
121→		sigBytes = line[:tabIdx]
122→		e.Message = string(line[tabIdx+1:])
123→	}
124→
125→	// Parse signature: Name <email> timestamp timezone
126→	open := bytes.LastIndexByte(sigBytes, '<')
127→	closeBracket := bytes.LastIndexByte(sigBytes, '>')
128→	if open == -1 || closeBracket == -1 || closeBracket < open {
129→		return nil, fmt.Errorf("invalid signature in reflog entry")
130→	}
131→
132→	e.Committer.Name = string(bytes.TrimSpace(sigBytes[:open]))
133→	e.Committer.Email = string(sigBytes[open+1 : closeBracket])
134→
135→	// Parse timestamp and timezone after '> '
136→	if closeBracket+2 >= len(sigBytes) {
137→		return nil, fmt.Errorf("missing timestamp in reflog entry")
138→	}
139→	var err error
140→	e.Committer.When, err = decodeTimestamp(sigBytes[closeBracket+2:])
141→	if err != nil {
142→		return nil, err
143→	}
144→
145→	return e, nil
146→}
147→
148→func decodeTimestamp(s []byte) (time.Time, error) {
149→	// Format: "1234567890 +0000"
150→	parts := bytes.Fields(s)
151→	if len(parts) != 2 {
152→		return time.Time{}, fmt.Errorf("invalid timestamp in reflog entry: %q", s)
153→	}
154→
155→	secs, err := strconv.ParseInt(string(parts[0]), 10, 64)
156→	if err != nil {
157→		return time.Time{}, fmt.Errorf("invalid timestamp seconds in reflog entry: %w", err)
158→	}
159→
160→	t := time.Unix(secs, 0)
161→
162→	tz := string(parts[1])
163→	if len(tz) != 5 || (tz[0] != '+' && tz[0] != '-') {
164→		return time.Time{}, fmt.Errorf("invalid timezone in reflog entry: %q", tz)
165→	}
166→	h, err := strconv.Atoi(tz[1:3])
167→	if err != nil {
168→		return time.Time{}, fmt.Errorf("invalid timezone hours in reflog entry: %w", err)
169→	}
170→	m, err := strconv.Atoi(tz[3:5])
171→	if err != nil {
172→		return time.Time{}, fmt.Errorf("invalid timezone minutes in reflog entry: %w", err)
173→	}
174→	offset := h*3600 + m*60
175→	if tz[0] == '-' {
176→		offset = -offset
177→	}
178→	t = t.In(time.FixedZone("", offset))
179→
180→	return t, nil
181→}
182→
183→// normalizeMessage normalizes a reflog message the same way Git does:
184→// collapse consecutive whitespace to a single space, strip leading/trailing
185→// whitespace, and remove newlines.
186→// See copy_reflog_msg in refs.c:
187→// https://github.com/git/git/blob/7ff1e8dc1e1680510c96e69965b3fa81372c5037/refs.c#L1026-L1049
188→func normalizeMessage(msg string) string {
189→	msg = strings.ReplaceAll(msg, "\n", " ")
190→	msg = strings.ReplaceAll(msg, "\r", " ")
191→	fields := strings.Fields(msg)
192→	return strings.Join(fields, " ")
193→}
194→
195→// Encode writes a single reflog entry to the writer.
196→func Encode(w io.Writer, e *Entry) error {
197→	if w == nil {
198→		return fmt.Errorf("writer is nil")
199→	}
200→	if e == nil {
201→		return fmt.Errorf("entry is nil")
202→	}
203→	_, offset := e.Committer.When.Zone()
204→	sign := '+'
205→	if offset < 0 {
206→		sign = '-'
207→		offset = -offset
208→	}
209→	hours := offset / 3600
210→	minutes := (offset % 3600) / 60
211→
212→	msg := normalizeMessage(e.Message)
213→
214→	if msg != "" {
215→		_, err := fmt.Fprintf(w, "%s %s %s <%s> %d %c%02d%02d\t%s\n",
216→			e.OldHash, e.NewHash,
217→			e.Committer.Name, e.Committer.Email,
218→			e.Committer.When.Unix(), sign, hours, minutes,
219→			msg,
220→		)
221→		return err
222→	}
223→
224→	_, err := fmt.Fprintf(w, "%s %s %s <%s> %d %c%02d%02d\n",
225→		e.OldHash, e.NewHash,
226→		e.Committer.Name, e.Committer.Email,
227→		e.Committer.When.Unix(), sign, hours, minutes,
228→	)
229→	return err
230→}
