  9→// ReflogStorage implements the storer.ReflogStorer for the transactional package.
 10→type ReflogStorage struct {
 11→	base     storer.ReflogStorer
 12→	temporal storer.ReflogStorer
 13→
 14→	// appended tracks refs that had entries appended during the transaction.
 15→	appended map[plumbing.ReferenceName]struct{}
 16→	// deleted tracks refs whose reflogs were deleted during the transaction.
 17→	deleted map[plumbing.ReferenceName]struct{}
 18→}
 19→
 20→// NewReflogStorage returns a new ReflogStorage based on a base storer and
 21→// a temporal storer.
 22→func NewReflogStorage(base, temporal storer.ReflogStorer) *ReflogStorage {
 23→	return &ReflogStorage{
 24→		base:     base,
 25→		temporal: temporal,
 26→		appended: make(map[plumbing.ReferenceName]struct{}),
 27→		deleted:  make(map[plumbing.ReferenceName]struct{}),
 28→	}
 29→}
 30→
 31→// Reflog honors the storer.ReflogStorer interface.
 32→// Returns base entries followed by temporal entries. If the reflog was
 33→// deleted during this transaction, only temporal entries (if any) are returned.
 34→func (s *ReflogStorage) Reflog(name plumbing.ReferenceName) ([]*reflog.Entry, error) {
 35→	if s == nil {
 36→		return nil, nil
 37→	}
 38→
 39→	var base []*reflog.Entry
 40→	if _, ok := s.deleted[name]; !ok {
 41→		var err error
 42→		base, err = s.base.Reflog(name)
 43→		if err != nil {
 44→			return nil, err
 45→		}
 46→	}
 47→
 48→	temporal, err := s.temporal.Reflog(name)
 49→	if err != nil {
 50→		return nil, err
 51→	}
 52→
 53→	if len(base) == 0 {
 54→		return temporal, nil
 55→	}
 56→	if len(temporal) == 0 {
 57→		return base, nil
 58→	}
 59→
 60→	result := make([]*reflog.Entry, 0, len(base)+len(temporal))
 61→	result = append(result, base...)
 62→	result = append(result, temporal...)
 63→	return result, nil
 64→}
 65→
 66→// AppendReflog honors the storer.ReflogStorer interface.
 67→func (s *ReflogStorage) AppendReflog(name plumbing.ReferenceName, entry *reflog.Entry) error {
 68→	if s == nil {
 69→		return nil
 70→	}
 71→	s.appended[name] = struct{}{}
 72→	return s.temporal.AppendReflog(name, entry)
 73→}
 74→
 75→// DeleteReflog honors the storer.ReflogStorer interface.
 76→func (s *ReflogStorage) DeleteReflog(name plumbing.ReferenceName) error {
 77→	if s == nil {
 78→		return nil
 79→	}
 80→	delete(s.appended, name)
 81→	s.deleted[name] = struct{}{}
 82→	return s.temporal.DeleteReflog(name)
 83→}
 84→
 85→// Commit flushes the transactional reflog changes into the base storage.
 86→func (s *ReflogStorage) Commit() error {
 87→	if s == nil {
 88→		return nil
 89→	}
 90→
 91→	for name := range s.deleted {
 92→		if err := s.base.DeleteReflog(name); err != nil {
 93→			return err
 94→		}
 95→	}
 96→
 97→	for name := range s.appended {
 98→		entries, err := s.temporal.Reflog(name)
 99→		if err != nil {
100→			return err
101→		}
102→		for _, e := range entries {
103→			if err := s.base.AppendReflog(name, e); err != nil {
104→				return err
105→			}
106→		}
107→	}
108→
109→	return nil
110→}
