	// Check raw config for explicit setting.
	val := cfg.Raw.Section("core").Options.Get("logallrefupdates")
	switch val {
	case "true", "always":
		return true
	case "false":
		return false
	default:
		// Default: true for non-bare, false for bare.
		return !cfg.Core.IsBare
	}
}

