 21→	"github.com/go-git/go-git/v6/storage/filesystem/dotgit"
 22→	xstorage "github.com/go-git/go-git/v6/x/storage"
 23→)
 24→
 25→const (
 26→	// names for dir and files managed by worktrees.
 27→	dotgitDir    = ".git"
 28→	worktrees    = "worktrees"
 29→	commonDir    = "commondir"
 30→	gitDir       = "gitdir"
 31→	head         = "HEAD"
 32→	originalHead = "ORIG_HEAD"
 33→	refs         = "refs"
 34→
 35→	dirMode               = 0o777
 36→	worktreeDotGitMaxSize = 1024
 37→)
 38→
 39→var (
 40→	worktreeNameRE = regexp.MustCompile(`^[a-zA-Z0-9\-]+$`)
 41→
 42→	// ErrWorktreeNotFound is returned when attempting to remove a worktree that does not exist.
 43→	ErrWorktreeNotFound = errors.New("worktree not found")
 44→
 45→	// ErrWorktreeAlreadyExists is returned when attempting to add a worktree with a name that already exists.
 46→	ErrWorktreeAlreadyExists = errors.New("worktree already exists")
 47→)
 48→
 49→// Worktree manages multiple working trees attached to a git repository.
 50→// It provides functionality to add and remove linked worktrees, allowing
 51→// multiple branches to be checked out simultaneously in different directories.
 52→//
 53→// A Worktree instance is tied to a specific repository through its storage
 54→// backend, which must implement the WorktreeStorer interface.
 55→type Worktree struct {
 56→	storer xstorage.WorktreeStorer
 57→}
 58→
 59→// New creates a new Worktree manager for the given storage backend.
 60→//
 61→// The storer must implement the WorktreeStorer interface, which provides
 62→// access to the repository's filesystem for managing worktree metadata.
 63→//
 64→// Returns an error if storer is nil or does not implement WorktreeStorer.
 65→func New(storer storage.Storer) (*Worktree, error) {
 66→	if storer == nil {
 67→		return nil, errors.New("storer is nil")
 68→	}
 69→
 70→	wts, ok := storer.(xstorage.WorktreeStorer)
 71→	if !ok {
 72→		return nil, errors.New("storer does not implement WorktreeStorer")
 73→	}
 74→
 75→	return &Worktree{
 76→		storer: wts,
 77→	}, nil
 78→}
 79→
 80→// Add creates a new linked worktree with the specified name and filesystem.
 81→//
 82→// This method sets up the necessary metadata and directory structure for a new
 83→// worktree, similar to the `git worktree add` command. The worktree will be
 84→// associated with the repository and can be used to work on a different commit
 85→// or branch simultaneously.
 86→func (w *Worktree) Add(wt billy.Filesystem, name string, opts ...Option) error {
 87→	if wt == nil {
 88→		return errors.New("cannot add worktree: fs is nil")
 89→	}
 90→
 91→	if !worktreeNameRE.MatchString(name) {
 92→		return fmt.Errorf("invalid worktree name %q", name)
 93→	}
 94→
 95→	o := &options{}
 96→	for _, opt := range opts {
 97→		opt(o)
 98→	}
