package main

import (
	"fmt"
	"os"
	"sort"
	"strings"

	"github.com/go-git/go-git/v6/plumbing"
)

func cmdBranch(args []string) int {
	var (
		doDelete      bool
		doMove        bool
		showCurrent   bool
		createReflog  bool
		positional    []string
	)

	for _, a := range args {
		switch a {
		case "-d", "--delete", "-D":
			doDelete = true
		case "-m", "--move", "-M":
			doMove = true
		case "--show-current":
			showCurrent = true
		case "-l", "--list":
			// default behavior
		case "-a", "--all":
			// show all (including remotes) — simplified
		case "-v", "--verbose":
			// accepted, ignored
		case "-q", "--quiet":
			// accepted, ignored
		case "--create-reflog":
			createReflog = true
		default:
			if !strings.HasPrefix(a, "-") {
				positional = append(positional, a)
			}
		}
	}

	repo := openRepoOrDie()

	if showCurrent {
		head, err := repo.Head()
		if err == nil && head.Name().IsBranch() {
			fmt.Println(head.Name().Short())
		}
		return 0
	}

	if doDelete {
		// Determine which branch HEAD points to (works even on orphan branches).
		head, _ := repo.Head()
		headRef, _ := repo.Storer.Reference(plumbing.HEAD)
		var currentBranch plumbing.ReferenceName
		if head != nil {
			currentBranch = head.Name()
		} else if headRef != nil && headRef.Type() == plumbing.SymbolicReference {
			currentBranch = headRef.Target()
		}
		for _, name := range positional {
			refName := plumbing.NewBranchReferenceName(name)
			if currentBranch == refName {
				fmt.Fprintf(os.Stderr, "error: cannot delete branch '%s' used by worktree at '%s'\n", name, ".")
				return 1
			}
			err := repo.Storer.RemoveReference(refName)
			if err != nil {
				fmt.Fprintf(os.Stderr, "error: branch '%s' not found.\n", name)
				return 1
			}
			deleteReflog(repo, refName)
			fmt.Printf("Deleted branch %s.\n", name)
		}
		return 0
	}

	if doMove {
		var oldRef, newRef plumbing.ReferenceName
		var hash plumbing.Hash

		if len(positional) == 2 {
			oldRef = plumbing.NewBranchReferenceName(positional[0])
			newRef = plumbing.NewBranchReferenceName(positional[1])

			ref, err := repo.Storer.Reference(oldRef)
			if err != nil {
				fmt.Fprintf(os.Stderr, "error: branch '%s' not found.\n", positional[0])
				return 1
			}
			hash = ref.Hash()
		} else if len(positional) == 1 {
			newRef = plumbing.NewBranchReferenceName(positional[0])
			head, err := repo.Head()
			if err != nil {
				fmt.Fprintln(os.Stderr, "fatal: not on any branch")
				return 128
			}
			oldRef = head.Name()
			hash = head.Hash()
		} else {
			fmt.Fprintln(os.Stderr, "fatal: too few arguments for branch rename")
			return 128
		}

		newReference := plumbing.NewHashReference(newRef, hash)
		if err := repo.Storer.SetReference(newReference); err != nil {
			fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
			return 128
		}
		if err := repo.Storer.RemoveReference(oldRef); err != nil {
			fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
			return 128
		}

		// Update HEAD if it pointed to the old branch.
		headRef, _ := repo.Storer.Reference(plumbing.HEAD)
		if headRef != nil && headRef.Type() == plumbing.SymbolicReference && headRef.Target() == oldRef {
			if err := repo.Storer.SetReference(plumbing.NewSymbolicReference(plumbing.HEAD, newRef)); err != nil {
				fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
				return 128
			}
			msg := fmt.Sprintf("Branch: renamed %s to %s", oldRef, newRef)
			appendReflog(repo, plumbing.HEAD, hash, hash, msg)
		}

		// Copy reflog from old to new, then delete old.
		deleteReflog(repo, oldRef)
		appendReflog(repo, newRef, plumbing.ZeroHash, hash,
			fmt.Sprintf("Branch: renamed %s to %s", oldRef, newRef))

		return 0
	}

	// Create branch.
	if len(positional) >= 1 {
		name := positional[0]
		head, err := repo.Head()
		if err != nil {
			fmt.Fprintln(os.Stderr, "fatal: not a valid object name: 'HEAD'")
			return 128
		}
		refName := plumbing.NewBranchReferenceName(name)

		// Check if branch already exists.
		if _, err := repo.Storer.Reference(refName); err == nil {
			fmt.Fprintf(os.Stderr, "fatal: a branch named '%s' already exists.\n", name)
			return 128
		}

		ref := plumbing.NewHashReference(refName, head.Hash())
		if err := repo.Storer.SetReference(ref); err != nil {
			fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
			return 128
		}

		if createReflog || shouldLogRefUpdates(repo) {
			appendReflog(repo, refName, plumbing.ZeroHash, head.Hash(),
				fmt.Sprintf("branch: Created from %s", head.Name().Short()))
		}
		return 0
	}

	// List branches.
	head, _ := repo.Head()
	currentBranch := ""
	if head != nil && head.Name().IsBranch() {
		currentBranch = head.Name().Short()
	}

	iter, err := repo.Branches()
	if err != nil {
		fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
		return 128
	}

	var branches []string
	iter.ForEach(func(ref *plumbing.Reference) error {
		branches = append(branches, ref.Name().Short())
		return nil
	})
	sort.Strings(branches)

	for _, b := range branches {
		if b == currentBranch {
			fmt.Printf("* %s\n", b)
		} else {
			fmt.Printf("  %s\n", b)
		}
	}

	return 0
}

package main

import (
	"os"
	"time"

	"github.com/go-git/go-git/v6"
	"github.com/go-git/go-git/v6/plumbing"
	"github.com/go-git/go-git/v6/plumbing/format/reflog"
	"github.com/go-git/go-git/v6/plumbing/storer"
)

// appendReflog appends a reflog entry if the storer supports reflogs.
func appendReflog(repo *git.Repository, name plumbing.ReferenceName, oldHash, newHash plumbing.Hash, msg string) {
	rs, ok := repo.Storer.(storer.ReflogStorer)
	if !ok {
		return
	}

	committerName := os.Getenv("GIT_COMMITTER_NAME")
	if committerName == "" {
		committerName = "Go-git CLI"
	}
	committerEmail := os.Getenv("GIT_COMMITTER_EMAIL")
	if committerEmail == "" {
		committerEmail = "go-git@localhost"
	}

	entry := &reflog.Entry{
		OldHash: oldHash,
		NewHash: newHash,
		Committer: reflog.Signature{
			Name:  committerName,
			Email: committerEmail,
			When:  time.Now(),
		},
		Message: msg,
	}

	rs.AppendReflog(name, entry)
}

// deleteReflog removes the reflog for a reference if the storer supports it.
func deleteReflog(repo *git.Repository, name plumbing.ReferenceName) {
	rs, ok := repo.Storer.(storer.ReflogStorer)
	if !ok {
		return
	}
	rs.DeleteReflog(name)
}

// shouldLogRefUpdates returns true if core.logAllRefUpdates is enabled.
// Git defaults to true for non-bare repos unless explicitly set to false.
func shouldLogRefUpdates(repo *git.Repository) bool {
	cfg, err := repo.Config()
	if err != nil {
		return false
	}

	// Check raw config for explicit setting.
	val := cfg.Raw.Section("core").Options.Get("logallrefupdates")
	switch val {
	case "true", "always":
		return true
	case "false":
		return false
	default:
		// Default: true for non-bare, false for bare.
		return !cfg.Core.IsBare
	}
}

