280→// buildTreeHelper converts a given index.Index file into multiple git objects
281→// reading the blobs from the given filesystem and creating the trees from the
282→// index structure. The created objects are pushed to a given Storer.
283→type buildTreeHelper struct {
284→	fs billy.Filesystem
285→	s  storage.Storer
286→
287→	trees   map[string]*object.Tree
288→	entries map[string]*object.TreeEntry
289→}
290→
291→// BuildTree builds the tree objects and push its to the storer, the hash
292→// of the root tree is returned.
293→func (h *buildTreeHelper) BuildTree(idx *index.Index, _ *CommitOptions) (plumbing.Hash, error) {
294→	const rootNode = ""
295→	h.trees = map[string]*object.Tree{rootNode: {}}
296→	h.entries = map[string]*object.TreeEntry{}
297→
298→	for _, e := range idx.Entries {
299→		if err := h.commitIndexEntry(e); err != nil {
300→			return plumbing.ZeroHash, err
301→		}
302→	}
303→
304→	return h.copyTreeToStorageRecursive(rootNode, h.trees[rootNode])
305→}
