			}
		case a == "--count":
			if i+1 < len(args) {
				i++ // skip value
			}
		case !strings.HasPrefix(a, "-"):
			patterns = append(patterns, a)
		}
		i++
	}

	_ = sortKey // TODO: sorting

	if format == "" {
		format = "%(objectname) %(objecttype)\t%(refname)"
	}

