func cmdReadTree(args []string) int {
	var (
		empty    bool
		merge    bool
		treeish  string
		treeish2 string
	)

	i := 0
	for i < len(args) {
		a := args[i]
		switch {
		case a == "--empty":
			empty = true
		case a == "-u":
			// update working tree — accepted, partially handled
		case a == "-m":
			merge = true
		case a == "--reset":
			merge = true
		case a == "-q", a == "--quiet":
			// accepted
		case !strings.HasPrefix(a, "-"):
			if treeish == "" {
				treeish = a
			} else {
				treeish2 = a
			}
		}
		i++
	}

	_ = merge

	repo := openRepoOrDie()

