package main

import (
	"fmt"
	"os"

	"github.com/go-git/go-git/v6"
)

func cmdAdd(args []string) int {
	var (
		all   bool
		paths []string
	)

	for _, a := range args {
		switch a {
		case "-A", "--all":
			all = true
		case "-u", "--update":
			all = true
		case "-n", "--dry-run":
			// accepted, ignored
		case "-v", "--verbose":
			// accepted, ignored
		case "-f", "--force":
			// accepted, ignored
		default:
			paths = append(paths, a)
		}
	}

	repo := openRepoOrDie()
	wt, err := repo.Worktree()
	if err != nil {
		fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
		return 128
	}

