 15→var (
 16→	pushProgress bool
 17→	pushPrune    bool
 18→	pushQuiet    bool
 19→	pushForce    bool
 20→)
 21→
 22→func init() {
 23→	pushCmd.Flags().BoolVarP(&pushQuiet, "quiet", "q", false, "Suppress all output unless an error occurs")
 24→	pushCmd.Flags().BoolVarP(&pushProgress, "progress", "", true, "Force show push progress")
 25→	pushCmd.Flags().BoolVarP(&pushPrune, "prune", "", false, "Prune remote branches")
 26→	pushCmd.Flags().BoolVarP(&pushForce, "force", "f", false, "Force push")
 27→
 28→	rootCmd.AddCommand(pushCmd)
 29→	rootCmd.CompletionOptions.HiddenDefaultCmd = true
 30→}
 31→
 32→var pushCmd = &cobra.Command{
 33→	Use:   "push [<options>] [--] [<repository> [<refspec>...]]",
 34→	Short: "Update remote refs along with associated objects",
 35→	RunE: func(cmd *cobra.Command, args []string) error {
 36→		r, err := git.PlainOpen(".")
 37→		if err != nil {
 38→			return err
 39→		}
 40→
 41→		cfg, err := r.Config()
 42→		if err != nil {
 43→			return fmt.Errorf("failed to get repository config: %w", err)
 44→		}
 45→
 46→		var ep *transport.Endpoint
 47→		remoteName := git.DefaultRemoteName
 48→		if len(args) > 0 {
 49→			isRemote := false
 50→			for remote := range cfg.Remotes {
 51→				if args[0] == remote {
 52→					remoteName = remote
 53→					isRemote = true
 54→
 55→					break
 56→				}
 57→			}
 58→			if !isRemote {
 59→				// Is this a repository URL?
 60→				ep, err = transport.NewEndpoint(args[0])
 61→				if err != nil {
 62→					// We have a remote name
 63→					remoteName = args[0]
 64→				}
 65→			}
 66→		}
 67→
 68→		var refspecs []config.RefSpec
 69→		if len(args) > 1 {
 70→			for _, arg := range args[1:] {
 71→				ref := plumbing.NewBranchReferenceName(arg)
 72→				str := fmt.Sprintf("+%s:refs/heads/%s", ref.String(), ref.Short())
 73→				refspecs = append(refspecs, config.RefSpec(str))
 74→			}
 75→		}
 76→
 77→		remote, err := r.Remote(remoteName)
 78→		if err != nil {
 79→			return err
 80→		}
 81→
 82→		if ep == nil {
 83→			// Use the default remote URL
 84→			urln := len(remote.Config().URLs) - 1
 85→			if urln < 0 {
 86→				return errors.New("no remote URLs")
 87→			}
 88→
 89→			ep, err = transport.NewEndpoint(remote.Config().URLs[urln])
 90→			if err != nil {
 91→				return err
 92→			}
 93→		}
 94→
 95→		opts := git.PushOptions{
 96→			Auth:       defaultAuth(ep),
 97→			RemoteName: remoteName,
 98→			RefSpecs:   refspecs,
 99→			Prune:      pushPrune,
100→			Force:      pushForce,
101→		}
102→
103→		var isatty bool
104→		stderr := cmd.ErrOrStderr()
105→		if f, ok := stderr.(interface {
106→			Fd() uintptr
107→		}); ok {
108→			isatty = term.IsTerminal(int(f.Fd()))
109→		}
110→
111→		if !pushQuiet && (isatty || pushProgress) {
112→			opts.Progress = cmd.ErrOrStderr()
113→		}
114→
115→		err = remote.Push(&opts)
116→		if errors.Is(err, git.NoErrAlreadyUpToDate) {
117→			cmd.PrintErr("Everything up-to-date")
118→
119→			return nil
120→		}
121→
122→		return err
123→	},
124→}
