  2→
  3→import (
  4→	"crypto"
  5→	"errors"
  6→	"fmt"
  7→	"io"
  8→	"log/slog"
  9→	"os"
 10→	"sort"
 11→	"strings"
 12→
 13→	"github.com/go-git/go-billy/v6"
 14→	fixtures "github.com/go-git/go-git-fixtures/v5"
 15→	"github.com/go-git/go-git/v6/plumbing"
 16→	"github.com/go-git/go-git/v6/plumbing/format/idxfile"
 17→	"github.com/go-git/go-git/v6/plumbing/format/packfile"
 18→	"github.com/spf13/cobra"
 19→)
 20→
 21→var (
 22→	verifyPackVerbose    bool
 23→	verifyPackFixtureUrl bool
 24→	verifyPackFixtureTag bool
 25→	verifyPackSHA256     bool
 26→)
 27→
 28→func init() {
 29→	verifyPackCmd.Flags().BoolVarP(&verifyPackVerbose, "verbose", "v", false, "Show detailed object information")
 30→	verifyPackCmd.Flags().BoolVarP(&verifyPackFixtureUrl, "fixture-url", "", false, "Use <file> as go-git-fixture url")
 31→	verifyPackCmd.Flags().BoolVarP(&verifyPackFixtureTag, "fixture-tag", "", false, "Use <file> as go-git-fixture tag")
 32→	verifyPackCmd.Flags().BoolVarP(&verifyPackSHA256, "sha256", "", false, "Treat the pack file as sha256")
 33→	rootCmd.AddCommand(verifyPackCmd)
 34→}
