 36→var verifyPackCmd = &cobra.Command{
 37→	Use:   "verify-pack [-v] <file>",
 38→	Short: "Validate packed Git archive files",
 39→	Args:  cobra.ExactArgs(1),
 40→	RunE: func(cmd *cobra.Command, args []string) error {
 41→		return verifyPack(args[0], verifyPackVerbose)
 42→	},
 43→	DisableFlagsInUseLine: true,
 44→}
 45→
 46→type objectInfo struct {
 47→	hash       plumbing.Hash
 48→	typ        plumbing.ObjectType
 49→	diskType   plumbing.ObjectType
 50→	size       int64
 51→	packedSize int64
 52→	offset     int64
 53→	depth      int
 54→	base       plumbing.Hash
 55→}
 56→
 57→func verifyPack(path string, verbose bool) error {
 58→	idxFile, packFile, err := openPack(path)
 59→	if err != nil {
 60→		return err
 61→	}
 62→
 63→	defer func() {
 64→		err = idxFile.Close()
 65→		if err != nil {
 66→			slog.Debug("failed to close idx file", "error", err)
 67→		}
 68→	}()
 69→
 70→	defer func() {
 71→		err = packFile.Close()
 72→		if err != nil {
 73→			slog.Debug("failed to close pack file", "error", err)
 74→		}
 75→	}()
 76→
 77→	ch := crypto.SHA1
 78→	if verifyPackSHA256 {
 79→		ch = crypto.SHA256
 80→	}
 81→
 82→	idx := idxfile.NewMemoryIndex(ch.Size())
 83→
 84→	dec := idxfile.NewDecoder(idxFile)
 85→	if err := dec.Decode(idx); err != nil {
 86→		return fmt.Errorf("failed to decode index file: %w", err)
 87→	}
 88→
 89→	pf := packfile.NewPackfile(
 90→		packFile,
 91→		packfile.WithIdx(idx),
 92→		packfile.WithObjectIDSize(ch.Size()),
 93→	)
 94→
 95→	defer func() {
 96→		err := pf.Close()
 97→		if err != nil {
 98→			slog.Debug("failed to close Packfile object", "error", err)
 99→		}
100→	}()
101→
102→	scanner, err := pf.Scanner() //nolint:staticcheck
103→	if err != nil {
104→		return fmt.Errorf("failed to get scanner: %w", err)
105→	}
106→
107→	entries, err := idx.EntriesByOffset()
108→	if err != nil {
109→		return fmt.Errorf("failed to get entries: %w", err)
110→	}
111→
112→	objects, err := collectObjectInfo(entries, scanner)
113→	if err != nil {
114→		return err
115→	}
116→
117→	// Calculate the packed size of the last object.
118→	if len(objects) > 0 {
119→		stat, err := packFile.Stat()
120→		if err != nil {
121→			return fmt.Errorf("failed to stat pack file: %w", err)
122→		}
123→		// Pack file ends with a checksum (20-byte SHA-1 or 32-byte SHA-256).
124→		objects[len(objects)-1].packedSize = stat.Size() - objects[len(objects)-1].offset - int64(ch.Size())
125→	}
126→
127→	// Resolve actual types for all objects (after delta application).
128→	for i := range objects {
129→		obj, err := pf.GetByOffset(objects[i].offset)
130→		if err != nil {
131→			return fmt.Errorf("failed to get object at offset %d: %w", objects[i].offset, err)
132→		}
133→
134→		objects[i].typ = obj.Type()
135→	}
136→
137→	deltaChains, err := calculateDeltaChains(objects, scanner)
138→	if err != nil {
139→		return err
140→	}
141→
142→	if verbose {
143→		printPackStatistics(objects, deltaChains)
144→	}
145→
146→	fmt.Printf("%s: ok\n", path)
147→
148→	return nil
149→}
150→
151→func openPack(path string) (billy.File, billy.File, error) {
152→	if verifyPackFixtureUrl || verifyPackFixtureTag {
153→		var f fixtures.Fixtures
154→		if verifyPackFixtureUrl {
155→			f = fixtures.ByURL(path)
156→		}
157→
158→		if verifyPackFixtureTag {
159→			f = fixtures.ByTag(path)
160→		}
161→
162→		if len(f) == 0 {
163→			return nil, nil, fmt.Errorf("no fixture found for %q", path)
164→		}
165→
166→		fixture := f.One()
167→
168→		return fixture.Idx(), fixture.Packfile(), nil
169→	}
170→
171→	idxPath := path
172→	packPath := path
173→
174→	if before, ok := strings.CutSuffix(path, ".idx"); ok {
175→		packPath = before + ".pack"
176→	} else if before, ok := strings.CutSuffix(path, ".pack"); ok {
177→		idxPath = before + ".idx"
178→	} else {
179→		return nil, nil, errors.New("file must have .idx or .pack extension")
180→	}
181→
182→	idxFile, err := os.Open(idxPath)
183→	if err != nil {
184→		return nil, nil, fmt.Errorf("failed to open index file: %w", err)
185→	}
186→
187→	packFile, err := os.Open(packPath)
188→	if err != nil {
189→		return nil, nil, fmt.Errorf("failed to open pack file: %w", err)
190→	}
191→
192→	return idxFile, packFile, nil
193→}
194→
195→// printPackStatistics outputs detailed object information and delta chain
196→// statistics to stdout.
197→func printPackStatistics(objects []objectInfo, deltaChains map[plumbing.Hash]int) {
198→	for _, obj := range objects {
199→		// Format type with padding to match git's output.
200→		typeStr := obj.typ.String()
201→		if len(typeStr) == 4 {
202→			typeStr = typeStr + "   "
203→		} else {
204→			typeStr = typeStr + " "
205→		}
206→
207→		fmt.Printf("%s %s%d %d %d",
208→			obj.hash.String(),
209→			typeStr,
210→			obj.size,
211→			obj.packedSize,
212→			obj.offset,
213→		)
214→
215→		if obj.diskType.IsDelta() && !obj.base.IsZero() {
216→			fmt.Printf(" %d %s", obj.depth, obj.base.String())
217→		}
218→
219→		fmt.Println()
220→	}
221→
222→	// Print statistics.
223→	nonDelta := len(objects) - len(deltaChains)
224→	fmt.Printf("non delta: %d objects\n", nonDelta)
225→
226→	// Count chain lengths.
227→	chainLengths := make(map[int]int)
228→	for _, depth := range deltaChains {
229→		chainLengths[depth]++
230→	}
231→
232→	// Sort chain lengths for consistent output.
233→	lengths := make([]int, 0, len(chainLengths))
234→	for length := range chainLengths {
235→		lengths = append(lengths, length)
236→	}
237→
238→	sort.Ints(lengths)
239→
240→	for _, length := range lengths {
241→		count := chainLengths[length]
242→
243→		objWord := "objects"
244→		if count == 1 {
245→			objWord = "object"
246→		}
247→
248→		fmt.Printf("chain length = %d: %d %s\n", length, count, objWord)
249→	}
250→}
251→
252→// calculateDeltaChains computes delta chain depth and base object references
253→// for all delta objects in the pack file.
254→//
255→//nolint:gocognit
256→func calculateDeltaChains(objects []objectInfo, scanner *packfile.Scanner) (map[plumbing.Hash]int, error) {
257→	deltaChains := make(map[plumbing.Hash]int)
258→	objectByHash := make(map[plumbing.Hash]*objectInfo)
259→	objectByOffset := make(map[int64]*objectInfo)
260→
261→	for i := range objects {
262→		objectByHash[objects[i].hash] = &objects[i]
263→		objectByOffset[objects[i].offset] = &objects[i]
264→	}
265→
266→	// Calculate delta chains by reading headers again.
267→	for i := range objects {
268→		if !objects[i].diskType.IsDelta() {
269→			continue
270→		}
271→
272→		err := scanner.SeekFromStart(objects[i].offset)
273→		if err != nil {
274→			return nil, fmt.Errorf("failed to seek to offset %d: %w", objects[i].offset, err)
275→		}
276→
277→		if !scanner.Scan() {
278→			return nil, fmt.Errorf("failed to scan object at offset %d", objects[i].offset)
279→		}
280→
281→		header, ok := scanner.Data().Value().(packfile.ObjectHeader)
282→		if !ok {
283→			return nil, errors.New("failed to scan pack header")
284→		}
285→
286→		// Calculate delta chain depth.
287→		depth := 1
288→
289→		var baseHash plumbing.Hash
290→
291→		//exhaustive:ignore only delta types needs handling.
292→		switch header.Type {
293→		case plumbing.REFDeltaObject:
294→			baseHash = header.Reference
295→		case plumbing.OFSDeltaObject:
296→			// OffsetReference is the absolute offset of the base object.
297→			if baseObj, ok := objectByOffset[header.OffsetReference]; ok {
298→				baseHash = baseObj.hash
299→			}
300→		}
301→
302→		// Follow the chain to calculate total depth.
303→		if !baseHash.IsZero() {
304→			current := baseHash
305→			for {
306→				baseObj, ok := objectByHash[current]
307→				if !ok {
308→					break
309→				}
310→
311→				if !baseObj.diskType.IsDelta() {
312→					// Reached a non-delta base.
313→					break
314→				}
315→
316→				// Get the base object's header.
317→				err := scanner.SeekFromStart(baseObj.offset)
318→				if err != nil {
319→					break
320→				}
321→
322→				if !scanner.Scan() {
323→					break
324→				}
325→
326→				baseHeader, ok := scanner.Data().Value().(packfile.ObjectHeader)
327→				if !ok {
328→					break
329→				}
330→
331→				depth++
332→
333→				if baseHeader.Type == plumbing.REFDeltaObject {
334→					current = baseHeader.Reference
335→				} else if baseHeader.Type == plumbing.OFSDeltaObject {
336→					// OffsetReference is the absolute offset.
337→					if nextBase, ok := objectByOffset[baseHeader.OffsetReference]; ok {
338→						current = nextBase.hash
339→					} else {
340→						break
341→					}
342→				} else {
343→					break
344→				}
345→			}
346→		}
347→
348→		objects[i].depth = depth
349→		objects[i].base = baseHash
350→		deltaChains[objects[i].hash] = depth
351→	}
352→
353→	return deltaChains, nil
354→}
355→
356→// collectObjectInfo reads all objects from the pack file and builds a list
357→// of object metadata including offsets and packed sizes.
358→func collectObjectInfo(entries idxfile.EntryIter, scanner *packfile.Scanner) ([]objectInfo, error) {
359→	var objects []objectInfo
360→
361→	for {
362→		entry, err := entries.Next()
363→		if errors.Is(err, io.EOF) {
364→			break
365→		}
366→
367→		if err != nil {
368→			return nil, fmt.Errorf("failed to read entry: %w", err)
369→		}
370→
371→		// Read raw object header to get delta information.
372→		err = scanner.SeekFromStart(int64(entry.Offset))
373→		if err != nil {
374→			return nil, fmt.Errorf("failed to seek to offset %d: %w", entry.Offset, err)
375→		}
376→
377→		if !scanner.Scan() {
378→			return nil, fmt.Errorf("failed to scan object at offset %d", entry.Offset)
379→		}
380→
381→		header, ok := scanner.Data().Value().(packfile.ObjectHeader)
382→		if !ok {
383→			return nil, errors.New("failed to scan pack header")
384→		}
385→
386→		// For delta objects, Size is the delta size.
387→		// For regular objects, Size is the inflated size.
388→		info := objectInfo{
389→			hash:     entry.Hash,
390→			diskType: header.Type,
391→			size:     header.Size,
392→			offset:   int64(entry.Offset),
393→		}
394→
395→		// Calculate packed size (distance to next header or end of file).
396→		if len(objects) > 0 {
397→			objects[len(objects)-1].packedSize = info.offset - objects[len(objects)-1].offset
398→		}
399→
400→		objects = append(objects, info)
401→	}
402→
403→	return objects, nil
404→}
